FACTORS_TOOL = {
    "name": "decision_factors",
    "description": "Break down the recommendation into the factors that drove it",
    "input_schema": {
        "type": "object",
        "properties": {
            "recommendation": {"type": "string"},
            "factors": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "name": {"type": "string"},
                        "importance": {"type": "integer", "minimum": 1, "maximum": 5},
                        "assessment": {"type": "string"},
                        "favours": {"type": "string", "enum": ["positive", "negative", "neutral"]},
                    },
                    "required": ["name", "importance", "assessment", "favours"],
                },
            },
            "summary": {"type": "string"},
        },
        "required": ["recommendation", "factors", "summary"],
    },
}

import anthropic

client = anthropic.Anthropic()

def recommend_with_factors(context: str, question: str) -> dict:
    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=1024,
        tools=[FACTORS_TOOL],
        tool_choice={"type": "tool", "name": "decision_factors"},
        messages=[
            {"role": "user", "content": f"Context:\n{context}\n\nQuestion: {question}"},
        ],
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    return {}

