COUNTERFACTUAL_TOOL = {
    "name": "counterfactual_explanation",
    "description": "Describe what inputs would change the recommendation",
    "input_schema": {
        "type": "object",
        "properties": {
            "current_recommendation": {"type": "string"},
            "alternatives": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "changed_input": {"type": "string"},
                        "new_recommendation": {"type": "string"},
                        "threshold": {"type": "string"},
                    },
                    "required": ["changed_input", "new_recommendation"],
                },
            },
        },
        "required": ["current_recommendation", "alternatives"],
    },
}

def explain_counterfactually(context: str, current_answer: str) -> dict:
    client = anthropic.Anthropic()
    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=512,
        tools=[COUNTERFACTUAL_TOOL],
        tool_choice={"type": "tool", "name": "counterfactual_explanation"},
        messages=[
            {
                "role": "user",
                "content": (
                    f"Context: {context}\n"
                    f"Current recommendation: {current_answer}\n\n"
                    "What changes to the input context would lead to a different recommendation? "
                    "List the most impactful 2-3 changes."
                ),
            }
        ],
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    return {}

